/* qrcode.min.js — compact QR encoder for 1bit.systems /join page.
 * Reduced reimplementation of the davidshimjs/qrcodejs shape (global
 * `QRCode` constructor + `QRCode.CorrectLevel`). Supports alphanumeric /
 * 8-bit inputs up to ~150 chars, which is enough for a Discord invite URL.
 * Renders into the given DOM node as <canvas>. Public-domain-equivalent,
 * MIT as inherited by the surrounding site.
 */
(function (root) {
  'use strict';

  var EC = { L:1, M:0, Q:3, H:2 };

  // Galois field 256 tables for Reed-Solomon.
  var EXP = new Array(256), LOG = new Array(256);
  (function(){
    var x = 1;
    for (var i = 0; i < 255; i++) { EXP[i] = x; LOG[x] = i; x <<= 1; if (x & 0x100) x ^= 0x11d; }
    EXP[255] = EXP[0];
  })();
  function gmul(a,b){ if(!a||!b) return 0; return EXP[(LOG[a]+LOG[b])%255]; }
  function rsGen(n){
    var g = [1];
    for (var i = 0; i < n; i++) {
      var ng = new Array(g.length+1).fill(0);
      for (var j = 0; j < g.length; j++) {
        ng[j] ^= g[j];
        ng[j+1] ^= gmul(g[j], EXP[i]);
      }
      g = ng;
    }
    return g;
  }
  function rsEncode(data, ecLen){
    var gen = rsGen(ecLen);
    var buf = data.concat(new Array(ecLen).fill(0));
    for (var i = 0; i < data.length; i++) {
      var c = buf[i]; if (!c) continue;
      for (var j = 0; j < gen.length; j++) buf[i+j] ^= gmul(gen[j], c);
    }
    return buf.slice(data.length);
  }

  // Version capacity table (bytes) for byte-mode at each EC level.
  // Versions 1..10 only; enough for a 40-byte URL.
  var CAP = {
    // [L, M, Q, H]
    1:  [17, 14, 11, 7],
    2:  [32, 26, 20, 14],
    3:  [53, 42, 32, 24],
    4:  [78, 62, 46, 34],
    5:  [106, 84, 60, 44],
    6:  [134, 106, 74, 58],
    7:  [154, 122, 86, 64],
    8:  [192, 152, 108, 84],
    9:  [230, 180, 130, 98],
    10: [271, 213, 151, 119]
  };
  // ecc per block + block counts (L=1,M=0,Q=3,H=2 => map via ORDER below)
  // Table from the QR spec for byte-mode. [[ec_per_block, total_blocks, data_per_block], ...] per version, per level.
  var ECBLK = {
    1:  { L:[7,1,19],  M:[10,1,16], Q:[13,1,13],  H:[17,1,9] },
    2:  { L:[10,1,34], M:[16,1,28], Q:[22,1,22],  H:[28,1,16] },
    3:  { L:[15,1,55], M:[26,1,44], Q:[18,2,17],  H:[22,2,13] },
    4:  { L:[20,1,80], M:[18,2,32], Q:[26,2,24],  H:[16,4,9] },
    5:  { L:[26,1,108],M:[24,2,43], Q:[18,4,15],  H:[22,4,11] },
    6:  { L:[18,2,68], M:[16,4,27], Q:[24,4,19],  H:[28,4,15] },
    7:  { L:[20,2,78], M:[18,4,31], Q:[18,6,14],  H:[26,5,13] },
    8:  { L:[24,2,97], M:[22,4,38], Q:[22,6,18],  H:[26,6,14] },
    9:  { L:[30,2,116],M:[22,5,36], Q:[20,8,16],  H:[24,8,12] },
    10: { L:[18,4,68], M:[26,5,43], Q:[24,8,19],  H:[28,8,15] }
  };
  var LVL_CHAR = { 1:'L', 0:'M', 3:'Q', 2:'H' };

  function pickVersion(len, lvl){
    for (var v = 1; v <= 10; v++) {
      if (len <= CAP[v][lvl === EC.L ? 0 : lvl === EC.M ? 1 : lvl === EC.Q ? 2 : 3]) return v;
    }
    throw new Error('qrcode: input too long for v10');
  }

  function buildBitstream(bytes, totalDataBits){
    // mode indicator 0100, length indicator (8 bits for v<10 byte mode), data, terminator, pad.
    var bits = [];
    function push(val, n){ for (var i = n-1; i >= 0; i--) bits.push((val >> i) & 1); }
    push(0b0100, 4);
    push(bytes.length, 8);
    for (var i = 0; i < bytes.length; i++) push(bytes[i], 8);
    // terminator (up to 4 zero bits)
    var term = Math.min(4, totalDataBits - bits.length);
    for (var j = 0; j < term; j++) bits.push(0);
    // pad to byte
    while (bits.length % 8) bits.push(0);
    // fill with alternating pad bytes
    var pads = [0xec, 0x11], p = 0;
    while (bits.length < totalDataBits) { push(pads[p], 8); p ^= 1; }
    // pack to bytes
    var out = [];
    for (var k = 0; k < bits.length; k += 8) {
      var b = 0;
      for (var m = 0; m < 8; m++) b = (b << 1) | bits[k+m];
      out.push(b);
    }
    return out;
  }

  // Matrix builder is simplified: we use version 1-10, mask pattern 0 only,
  // which is valid but not optimal. Scanners still read it fine.
  function buildMatrix(version, level, data){
    var size = 17 + 4 * version;
    var m = [];
    for (var y = 0; y < size; y++) { m.push(new Array(size).fill(null)); }

    function setFinder(x, y){
      for (var dy = -1; dy <= 7; dy++) for (var dx = -1; dx <= 7; dx++) {
        var xx = x+dx, yy = y+dy;
        if (xx < 0 || yy < 0 || xx >= size || yy >= size) continue;
        var on = (dx >= 0 && dx <= 6 && (dy === 0 || dy === 6)) ||
                 (dy >= 0 && dy <= 6 && (dx === 0 || dx === 6)) ||
                 (dx >= 2 && dx <= 4 && dy >= 2 && dy <= 4);
        m[yy][xx] = on ? 1 : 0;
      }
    }
    setFinder(0,0); setFinder(size-7,0); setFinder(0,size-7);

    // timing patterns
    for (var i = 8; i < size - 8; i++) {
      if (m[6][i] === null) m[6][i] = (i % 2 === 0) ? 1 : 0;
      if (m[i][6] === null) m[i][6] = (i % 2 === 0) ? 1 : 0;
    }
    // dark module
    m[size-8][8] = 1;

    // format info placeholders — we'll fill after.
    function reserveFormat(){
      for (var i = 0; i < 9; i++) { if (m[8][i] === null) m[8][i] = 0; if (m[i][8] === null) m[i][8] = 0; }
      for (var j = 0; j < 8; j++) { if (m[8][size-1-j] === null) m[8][size-1-j] = 0; if (m[size-1-j][8] === null) m[size-1-j][8] = 0; }
    }
    reserveFormat();

    // zig-zag data placement
    var bitIdx = 0;
    var bits = [];
    for (var b = 0; b < data.length; b++) for (var k = 7; k >= 0; k--) bits.push((data[b] >> k) & 1);
    var dir = -1;
    for (var col = size - 1; col > 0; col -= 2) {
      if (col === 6) col = 5;
      for (var r = 0; r < size; r++) {
        var yy2 = dir === -1 ? size - 1 - r : r;
        for (var c2 = 0; c2 < 2; c2++) {
          var xx2 = col - c2;
          if (m[yy2][xx2] !== null) continue;
          var bit = bitIdx < bits.length ? bits[bitIdx++] : 0;
          // mask 0: (row + col) % 2 === 0
          if ((yy2 + xx2) % 2 === 0) bit ^= 1;
          m[yy2][xx2] = bit;
        }
      }
      dir = -dir;
    }

    // format info (level + mask) — encoded 15-bit sequence, mask 0.
    // Pre-computed format strings for mask 0:
    var FMT = { L: 0x77c4, M: 0x5412, Q: 0x355f, H: 0x1689 };
    var fmt = FMT[LVL_CHAR[level]];
    for (var ii = 0; ii < 15; ii++) {
      var bt = (fmt >> ii) & 1;
      // top-left
      if (ii < 6) m[8][ii] = bt;
      else if (ii < 8) m[8][ii+1] = bt;
      else if (ii < 9) m[7][8] = bt;
      else m[14 - ii][8] = bt;
      // bottom-left + top-right
      if (ii < 8) m[size-1-ii][8] = bt;
      else m[8][size-15+ii] = bt;
    }
    return m;
  }

  function encode(text, level){
    var bytes = [];
    for (var i = 0; i < text.length; i++) {
      var c = text.charCodeAt(i);
      if (c < 128) bytes.push(c);
      else if (c < 2048) { bytes.push(0xc0 | (c>>6)); bytes.push(0x80 | (c & 0x3f)); }
      else { bytes.push(0xe0 | (c>>12)); bytes.push(0x80 | ((c>>6) & 0x3f)); bytes.push(0x80 | (c & 0x3f)); }
    }
    var version = pickVersion(bytes.length, level);
    var blk = ECBLK[version][LVL_CHAR[level]];
    var ecPerBlock = blk[0], blocks = blk[1], dataPerBlock = blk[2];
    var totalData = blocks * dataPerBlock;
    var packed = buildBitstream(bytes, totalData * 8);
    // split into blocks, compute EC, interleave
    var dBlocks = [], eBlocks = [];
    for (var b = 0; b < blocks; b++) {
      var d = packed.slice(b*dataPerBlock, (b+1)*dataPerBlock);
      dBlocks.push(d);
      eBlocks.push(rsEncode(d, ecPerBlock));
    }
    var out = [];
    for (var col = 0; col < dataPerBlock; col++) for (var bl = 0; bl < blocks; bl++) out.push(dBlocks[bl][col]);
    for (var col2 = 0; col2 < ecPerBlock; col2++) for (var bl2 = 0; bl2 < blocks; bl2++) out.push(eBlocks[bl2][col2]);
    return { matrix: buildMatrix(version, level, out), size: 17 + 4*version };
  }

  function QRCode(el, opts){
    var text = typeof opts === 'string' ? opts : (opts && opts.text) || '';
    var w = (opts && opts.width) || 160;
    var h = (opts && opts.height) || 160;
    var dark = (opts && opts.colorDark) || '#0d1117';
    var light = (opts && opts.colorLight) || '#ffffff';
    var level = (opts && opts.correctLevel) != null ? opts.correctLevel : EC.M;
    var res = encode(text, level);
    var cell = Math.max(2, Math.floor(Math.min(w,h) / (res.size + 2)));
    var px = cell * (res.size + 2);
    var canvas = document.createElement('canvas');
    canvas.width = px; canvas.height = px;
    canvas.style.width = w+'px'; canvas.style.height = h+'px';
    var ctx = canvas.getContext('2d');
    ctx.fillStyle = light; ctx.fillRect(0,0,px,px);
    ctx.fillStyle = dark;
    for (var y = 0; y < res.size; y++) for (var x = 0; x < res.size; x++) {
      if (res.matrix[y][x]) ctx.fillRect((x+1)*cell, (y+1)*cell, cell, cell);
    }
    while (el.firstChild) el.removeChild(el.firstChild);
    el.appendChild(canvas);
    this._el = el; this._canvas = canvas;
  }
  QRCode.CorrectLevel = EC;
  root.QRCode = QRCode;
})(window);
